import React, { useState, useEffect } from 'react';
import './App.css';
import Topo from "./componentes/Topo";
import Rodape from "./componentes/Rodape" ;

function App() {
  const [produtos, setProdutos] = useState([]);
  const [carrinho, setCarrinho] = useState([]);
  const [modoCadastro, setModoCadastro] = useState(false);
  const [formData, setFormData] = useState({ nome: '', email: '', senha: '', cpf: '', telefone: '', cep: '', endereco: '' });
  // Controle de Navegação: 'vitrine', 'carrinho', 'login', 'checkout', 'sucesso'
  const [etapa, setEtapa] = useState('vitrine'); 
  
  // Dados do Usuário e Pagamento
  const [usuario, setUsuario] = useState(null); 
  const [formaPagamento, setFormaPagamento] = useState('');
  const [pedidoFinalizado, setPedidoFinalizado] = useState(null);

  // FUNÇÃO DE LOGIN REAL
  const handleLogin = () => {
    fetch("http://localhost:3001/login", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email: formData.email, senha: formData.senha })
    })
    .then(res => res.ok ? res.json() : Promise.reject())
    .then(user => {
      setUsuario(user);
      setEtapa('checkout');
    })
    .catch(() => alert("Usuário não encontrado! Cadastre-se."));
  };

  // FUNÇÃO DE FINALIZAR NO BANCO
  const confirmarPedidoNoBanco = () => {
    const numPedido = Math.floor(100000 + Math.random() * 900000);
    
    fetch("http://localhost:3001/finalizar-pedido", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ id_pedido: numPedido, itens: carrinho })
    })
    .then(() => {
      setPedidoFinalizado({ numero: numPedido, total: totalFinal });
      setEtapa('sucesso');
    });
  };

  // Busca produtos do Backend
  useEffect(() => {
    fetch("http://localhost:3001/produtos")
      .then(res => res.json())
      .then(dados => setProdutos(dados))
      .catch(err => console.error("Erro ao carregar produtos:", err));
  }, []);

  // Lógica do Carrinho
  const adicionarAoCarrinho = (produto) => {
    const existe = carrinho.find(x => x.id === produto.id);
    if (existe) {
      setCarrinho(carrinho.map(x => x.id === produto.id ? { ...existe, qtd: existe.qtd + 1 } : x));
    } else {
      setCarrinho([...carrinho, { ...produto, qtd: 1 }]);
    }
    setEtapa('carrinho'); // Abre o carrinho automaticamente ao comprar
  };


  const alterarQtd = (id, operacao) => {
    setCarrinho(carrinho.map(item => {
      if (item.id === id) {
        const novaQtd = operacao === '+' ? item.qtd + 1 : item.qtd - 1;
        return { ...item, qtd: novaQtd > 0 ? novaQtd : 1 };
      }
      return item;
    }));
  };

  // Cálculos de Valores
  const totalProdutos = carrinho.reduce((acc, item) => acc + (item.valor * item.qtd), 0);
  const valorFrete = formaPagamento === 'pix' ? 0 : 15.00;
  const totalFinal = totalProdutos + valorFrete;

  // Função para Finalizar Pedido
  const finalizarPedido = () => {
    const numeroAleatorio = Math.floor(100000 + Math.random() * 900000);
    const dadosPedido = {
      numero: numeroAleatorio,
      itens: carrinho,
      total: totalFinal,
      pagamento: formaPagamento,
      status: 'Em andamento'
    };
    setPedidoFinalizado(dadosPedido);
    setEtapa('sucesso');
    setCarrinho([]); // Limpa o carrinho
  };

  return (
    <div className="App">
      {/* O Topo recebe se o usuário está logado para mostrar o Histórico */}
      <Topo 
        totalItens={carrinho.length} 
        abrirCarrinho={() => setEtapa('carrinho')} 
        temPedido={!!pedidoFinalizado} 
      />
      <main>
        {/* TELA DE LOGIN / CADASTRO */}
        {etapa === 'login' && (
          <div className="container-checkout">
            <h2>{modoCadastro ? "📝 Cadastro" : "🔐 Login"}</h2>
            <input type="email" placeholder="E-mail" onChange={e => setFormData({...formData, email: e.target.value})} />
            <input type="password" placeholder="Senha" onChange={e => setFormData({...formData, senha: e.target.value})} />
            
            {modoCadastro && (
              <>
                <input type="text" placeholder="Nome Completo" onChange={e => setFormData({...formData, nome: e.target.value})} />
                <input type="text" placeholder="CPF" onChange={e => setFormData({...formData, cpf: e.target.value})} />
                <input type="text" placeholder="CEP" onChange={e => setFormData({...formData, cep: e.target.value})} />
                <input type="text" placeholder="Endereço" onChange={e => setFormData({...formData, endereco: e.target.value})} />
                <input type="text" placeholder="Telefone" onChange={e => setFormData({...formData, telefone: e.target.value})} />
              </>
            )}

            <button onClick={modoCadastro ? handleCadastro : handleLogin}>
              {modoCadastro ? "Finalizar Cadastro" : "Entrar"}
            </button>
            <p onClick={() => setModoCadastro(!modoCadastro)} style={{cursor:'pointer', color:'blue'}}>
              {modoCadastro ? "Já tenho conta" : "Não tenho conta? Cadastrar"}
            </p>
          </div>
        )}

        {/* TELA DE CHECKOUT (Mostrando dados do cliente logado) */}
        {etapa === 'checkout' && usuario && (
          <div className="container-checkout">
            <h2>📍 Confirmar Dados</h2>
            <p><strong>Cliente:</strong> {usuario.nome}</p>
            <p><strong>Telefone:</strong> {usuario.telefone}</p>
            <p><strong>Entrega:</strong> {usuario.endereco}, {usuario.cep}</p>
            <button onClick={confirmarPedidoNoBanco}>Confirmar e Gerar Pedido</button>
          </div>
        )}
      </main>

      <main className="conteudo-principal">
        
        {/* TELA 1: VITRINE */}
        {etapa === 'vitrine' && (
          <div className="grid-produtos">
            {produtos.map((item) => (
              <div key={item.id} className="card">
                <img src={item.imagem_url} alt={item.produto} />
                <h3>{item.produto}</h3>
                <p className="preco">R$ {parseFloat(item.valor).toFixed(2)}</p>
                <small>Estoque: {item.estoque}</small>
                <button onClick={() => adicionarAoCarrinho(item)}>Comprar</button>
              </div>
            ))}
          </div>
        )}

        {/* TELA 2: CARRINHO */}
        {etapa === 'carrinho' && (
          <div className="container-checkout">
            <h2>🛒 Seu Carrinho</h2>
            {carrinho.length === 0 ? <p>Carrinho vazio...</p> : (
              <>
                {carrinho.map(item => (
                  <div key={item.id} className="item-lista">
                    <span>{item.produto}</span>
                    <div className="controles-qtd">
                      <button onClick={() => alterarQtd(item.id, '-')}>-</button>
                      <span>{item.qtd}</span>
                      <button onClick={() => alterarQtd(item.id, '+')}>+</button>
                    </div>
                    <span>R$ {(item.valor * item.qtd).toFixed(2)}</span>
                  </div>
                ))}
                <h3 className="subtotal">Subtotal: R$ {totalProdutos.toFixed(2)}</h3>
                <div style={{display: 'flex', gap: '10px', justifyContent: 'center'}}>
                <button className="btn-voltar" onClick={() => setEtapa('vitrine')}>Voltar</button>
                <button className="btn-proximo" onClick={() => setEtapa('login')}>Finalizar Pedido</button>
                </div>
              </>
            )}
          </div>
        )}

        {/* TELA 3: LOGIN */}
        {etapa === 'login' && (
          <div className="container-checkout">
            <h2>🔐 Identificação</h2>
            <div className="form-login">
              <input type="text" placeholder="E-mail ou CPF" />
              <input type="password" placeholder="Senha" />
              <button className="btn-proximo" onClick={() => {
                setUsuario({ nome: "Pollyanna Santos", cep: "09300-000", endereco: "Rua Principal, 100", cidade: "Mauá" });
                setEtapa('checkout');
              }}>Entrar e Continuar</button>
            </div>
          </div>
        )}

        {/* TELA 4: CHECKOUT */}
        {etapa === 'checkout' && (
          <div className="container-checkout">
          <h2>📍 Revisão do Pedido</h2>
    <div className="painel-dados" style={{textAlign: 'left', marginBottom: '20px'}}>
      <p><strong>Entregar em:</strong> {usuario?.endereco}, {usuario?.cidade}</p>
    </div>

    <h3>💳 Selecione o Pagamento</h3>
    <select 
      className="select-pagamento" 
      value={formaPagamento} 
      onChange={(e) => setFormaPagamento(e.target.value)}
    >
      <option value="">Escolha como pagar...</option>
      <option value="pix">Pix (Frete R$ 0,00 🎁)</option>
      <option value="credito">Cartão de Crédito (Frete R$ 15,00)</option>
      <option value="debito">Cartão de Débito (Frete R$ 15,00)</option>
      <option value="alimentacao">Cartão Alimentação (Frete R$ 15,00)</option>
    </select>

    <div className="resumo-financeiro" style={{background: '#f9f9f9', padding: '15px', borderRadius: '8px', marginTop: '20px'}}>
      <p style={{display: 'flex', justifyContent: 'space-between'}}>
        <span>Pedido:</span> 
        <span>R$ {totalProdutos.toFixed(2)}</span>
      </p>
      <p style={{display: 'flex', justifyContent: 'space-between', color: formaPagamento === 'pix' ? 'green' : 'black'}}>
        <span>Frete:</span> 
        <span>{formaPagamento === 'pix' ? "R$ 0.00" : `R$ ${valorFrete.toFixed(2)}`}</span>
      </p>
      <hr />
      <h3 style={{display: 'flex', justifyContent: 'space-between'}}>
        <span>Total:</span> 
        <span>R$ {totalFinal.toFixed(2)}</span>
      </h3>
    </div>

    <button 
      className="btn-confirmar" 
      disabled={!formaPagamento} 
      onClick={finalizarPedido}
      style={{backgroundColor: !formaPagamento ? '#ccc' : '#28a745'}}
    >
      Finalizar e Pagar
    </button>
  </div>
)}
        {/* TELA 5: SUCESSO */}
        {etapa === 'sucesso' && (
          <div className="alerta-sucesso">
    <div style={{fontSize: '3rem'}}>✅</div>
    <h3>Pedido #{pedidoFinalizado.numero} Realizado!</h3>
    <p>Status: <span style={{color: 'orange', fontWeight: 'bold'}}>{pedidoFinalizado.status}</span></p>
    
    <div style={{textAlign: 'left', borderTop: '1px solid #ccc', marginTop: '15px', paddingTop: '10px'}}>
      <p><strong>Resumo Financeiro:</strong></p>
      <p>Pedido: R$ {totalProdutos.toFixed(2)}</p>
      <p>Frete: R$ {pedidoFinalizado.pagamento === 'pix' ? "0.00" : "15.00"}</p>
      <h4 style={{fontSize: '1.2rem'}}>Total: R$ {pedidoFinalizado.total.toFixed(2)}</h4>
    </div>

    <button 
      className="btn-proximo" 
      onClick={() => setEtapa('vitrine')}
      style={{marginTop: '20px'}}
    >
      Voltar para a Loja
    </button>
  </div>
)}

      </main>

      <Rodape />
    </div>
  );
}

export default App;
